// Helper: registry check for installed apps
function regCheck(n) {
  return `if(Get-ItemProperty "HKLM:\\\\Software\\\\Microsoft\\\\Windows\\\\CurrentVersion\\\\Uninstall\\\\*","HKLM:\\\\Software\\\\WOW6432Node\\\\Microsoft\\\\Windows\\\\CurrentVersion\\\\Uninstall\\\\*","HKCU:\\\\Software\\\\Microsoft\\\\Windows\\\\CurrentVersion\\\\Uninstall\\\\*" -EA Ignore|Where-Object{$_.DisplayName -match "${n}"}){echo "true"}`;
}

